updates.replacement:
extra_context_object
    : '{}'
    | '{' "project_name" ':' '"Overwritten Project"' '}'
    | '{' "use_docker" ':' '"true"' '}'
    // nested dictionary to trigger generate.py nested variable handling
    | '{' "nested" ':' '{' "inner" ':' '"value"' '}' '}'
    // list value to test list merging logic
    | '{' "license" ':' '[' '"MIT"' ',' '"GPL"' ']' '}'
    ;

template_source
    : '"local"'
    // remote zip archive URL
    | '"https://example.com/template.zip"'
    // VCS URL (git or hg)
    | '"git+https://github.com/user/repo.git"'
    | '"hg+https://hg.example.com/user/repo"'
    ;
